import React, { useState } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton,
  useMediaQuery,
  TextField,
  Stepper,
  Step,
  StepLabel,
  StepButton,
  LinearProgress
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import VerifiedUserIcon from '@mui/icons-material/VerifiedUser';
import FormatQuoteIcon from '@mui/icons-material/FormatQuote';
import EditIcon from '@mui/icons-material/Edit';
import SendIcon from '@mui/icons-material/Send';
import WarningAmberIcon from '@mui/icons-material/WarningAmber';
import TipsAndUpdatesIcon from '@mui/icons-material/TipsAndUpdates';
import VerifiedIcon from '@mui/icons-material/Verified';
import CelebrationOutlinedIcon from '@mui/icons-material/CelebrationOutlined';

const TestimonialMascot = ({ size = 'medium', color = 'primary' }) => {
  const theme = useTheme();
  const sizeMap = {
    small: { width: 40, height: 40, quoteSize: 'small' },
    medium: { width: 60, height: 60, quoteSize: 'medium' },
    large: { width: 80, height: 80, quoteSize: 'large' }
  };

  const dims = sizeMap[size];

  return (
    <Box
      sx={{
        position: 'relative',
        width: dims.width,
        height: dims.height,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}
    >
      {/* Speech bubble shape */}
      <Box
        sx={{
          width: '100%',
          height: '100%',
          borderRadius: '50%',
          background: theme => theme.palette[color].main,
          position: 'relative',
          '&::after': {
            content: '""',
            position: 'absolute',
            bottom: '-10px',
            right: '10px',
            width: '20px',
            height: '20px',
            background: theme => theme.palette[color].main,
            borderRadius: '50%',
            transform: 'scale(0.5)'
          },
          '&::before': {
            content: '""',
            position: 'absolute',
            bottom: '-18px',
            right: '0',
            width: '15px',
            height: '15px',
            background: theme => theme.palette[color].main,
            borderRadius: '50%',
            transform: 'scale(0.3)'
          }
        }}
      />

      {/* Quote icon */}
      <FormatQuoteIcon 
        sx={{ 
          position: 'absolute', 
          color: 'white',
          transform: 'rotate(180deg)',
          fontSize: dims.quoteSize === 'small' ? '1.5rem' : 
                   dims.quoteSize === 'medium' ? '2rem' : '2.5rem'
        }} 
      />

      {/* Eyes */}
      <Box
        sx={{
          position: 'absolute',
          top: '30%',
          left: '25%',
          width: '8px',
          height: '8px',
          borderRadius: '50%',
          background: 'white'
        }}
      />
      <Box
        sx={{
          position: 'absolute',
          top: '30%',
          right: '25%',
          width: '8px',
          height: '8px',
          borderRadius: '50%',
          background: 'white'
        }}
      />

      {/* Smile */}
      <Box
        sx={{
          position: 'absolute',
          bottom: '30%',
          left: '50%',
          transform: 'translateX(-50%)',
          width: '20px',
          height: '10px',
          borderBottomLeftRadius: '10px',
          borderBottomRightRadius: '10px',
          border: '2px solid white',
          borderTop: 'none'
        }}
      />
    </Box>
  );
};

const TestimonialStarMascot = ({ size = 'medium', color = 'primary' }) => {
  const sizeMap = {
    small: { width: 40, height: 40 },
    medium: { width: 60, height: 60 },
    large: { width: 80, height: 80 }
  };

  const dims = sizeMap[size];

  return (
    <Box
      sx={{
        position: 'relative',
        width: dims.width,
        height: dims.height,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}
    >
      {/* Star shape */}
      <StarIcon 
        sx={{ 
          position: 'absolute',
          width: '100%',
          height: '100%',
          color: theme => theme.palette[color].main,
          filter: 'drop-shadow(0 2px 5px rgba(0,0,0,0.2))'
        }} 
      />

      {/* Eyes */}
      <Box
        sx={{
          position: 'absolute',
          top: '35%',
          left: '30%',
          width: '6px',
          height: '6px',
          borderRadius: '50%',
          background: 'white'
        }}
      />
      <Box
        sx={{
          position: 'absolute',
          top: '35%',
          right: '30%',
          width: '6px',
          height: '6px',
          borderRadius: '50%',
          background: 'white'
        }}
      />

      {/* Smile */}
      <Box
        sx={{
          position: 'absolute',
          bottom: '35%',
          left: '50%',
          transform: 'translateX(-50%)',
          width: '16px',
          height: '8px',
          borderBottomLeftRadius: '8px',
          borderBottomRightRadius: '8px',
          border: '2px solid white',
          borderTop: 'none'
        }}
      />
    </Box>
  );
};

const HomePage = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const [activeStep, setActiveStep] = useState(0);
  const [completed, setCompleted] = useState({});
  const [originalScores, setOriginalScores] = useState({ emotional: 0, specificity: 0, credibility: 0 });
  const [enhancedScores, setEnhancedScores] = useState({ emotional: 0, specificity: 0, credibility: 0 });
  const [spotlightActive, setSpotlightActive] = useState(false);

  const steps = [
    'Enter original testimonial',
    'Get AI enhancement',
    'Client verification'
  ];

  const originalText = "The coaching was good. I learned some things that helped me.";
  const enhancedText = "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible.";

  const handleStep = (step) => () => {
    setActiveStep(step);

    // Mark previous steps as completed
    const newCompleted = {...completed};
    for (let i = 0; i < step; i++) {
      newCompleted[i] = true;
    }
    setCompleted(newCompleted);
  };

  const handleNext = () => {
    const newCompleted = {...completed};
    newCompleted[activeStep] = true;
    setCompleted(newCompleted);
    setActiveStep((prevActiveStep) => prevActiveStep + 1);
  };

  const handleReset = () => {
    setActiveStep(0);
    setCompleted({});
    setOriginalScores({ emotional: 0, specificity: 0, credibility: 0 });
    setEnhancedScores({ emotional: 0, specificity: 0, credibility: 0 });
    setSpotlightActive(false);
  };

  const getScoreColor = (score) => {
    if (score < 50) return 'error.main';
    if (score < 75) return 'warning.main';
    return 'success.main';
  };

  return (
    <Box sx={{ overflow: 'hidden' }}>
      {/* Hero Section */}
      <Box 
        sx={{
          pt: { xs: 6, md: 8 },
          pb: { xs: 8, md: 10 },
          position: 'relative',
          minHeight: '80vh',
          display: 'flex',
          alignItems: 'center'
        }}
      >
        {/* Background gradient */}
        <Box 
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'linear-gradient(180deg, rgba(93, 95, 239, 0.05) 0%, rgba(93, 95, 239, 0) 100%)',
            zIndex: -1
          }}
        />

        <Container maxWidth="lg" sx={{ position: 'relative' }}>
          <Box sx={{ display: 'flex', flexDirection: { xs: 'column', md: 'row' }, alignItems: 'center' }}>
            {/* Left side - Hero text */}
            <Box sx={{ width: { xs: '100%', md: '50%' }, pr: { md: 6 }, mb: { xs: 6, md: 0 } }}>
              <Chip
                icon={<AutoAwesomeIcon />}
                label="AI-Powered Testimonials"
                sx={{ 
                  mb: 3, 
                  bgcolor: 'primary.light', 
                  color: 'primary.dark',
                  fontWeight: 600,
                  '& .MuiChip-icon': { color: 'primary.main' }
                }}
              />

              <Typography 
                variant="h2" 
                component="h1" 
                gutterBottom
                sx={{ 
                  fontWeight: 700,
                  fontSize: { xs: '2.5rem', md: '3.5rem' },
                  lineHeight: 1.2
                }}
              >
                Turn <Box component="span" sx={{ color: 'primary.main' }}>"It was good"</Box> into testimonials that sell
              </Typography>

              <Typography variant="subtitle1" color="text.secondary" sx={{ mb: 4, fontSize: '1.1rem' }}>
                Enhance bland client feedback into compelling stories that showcase your true impact—with AI that captures transformation, emotion, and results.
              </Typography>

              <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2}>
                <Button 
                  variant="contained" 
                  color="primary"
                  size="large"
                  component={RouterLink}
                  to="/enhance"
                  sx={{ px: 3, py: 1.5 }}
                  endIcon={<ArrowForwardIcon />}
                >
                  Enhance a Testimonial
                </Button>

                <Button 
                  variant="outlined" 
                  color="primary"
                  size="large"
                  startIcon={<PlayArrowIcon />}
                  sx={{ px: 3, py: 1.5 }}
                  onClick={handleReset}
                >
                  Try Demo
                </Button>
              </Stack>

              <Box sx={{ display: 'flex', alignItems: 'center', mt: 4 }}>
                <Box sx={{ display: 'flex', mr: 1.5 }}>
                  {[...Array(5)].map((_, i) => (
                    <StarIcon key={i} sx={{ color: '#FFD700', fontSize: 20 }} />
                  ))}
                </Box>
                <Typography variant="body2" color="text.secondary">
                  <Box component="span" sx={{ fontWeight: 600, color: 'text.primary' }}>4.9/5</Box> from 200+ users
                </Typography>
              </Box>
            </Box>

            {/* Right side - Interactive Demo */}
            <Box 
              sx={{ 
                width: { xs: '100%', md: '50%' },
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'flex-start',
                mt: { xs: 2, md: 0 }
              }}
